var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"도, 도망쳐! 침식체다!","JPN":"に、逃げろ！侵食体だ！","ENG":"R-run! It's a C.O.!","TWN":"快、快逃！是侵蝕體！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"으아아앙, 엄마! 아빠! 어딨어?","JPN":"うわあああん、ママ！パパ！どこにいるの？","ENG":"Wahhhh, Mommy! Daddy! Where are you?","TWN":"嗚啊啊啊啊，媽媽！爸爸！你們在哪？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 안돼! 우리 집이......! 저기엔 내 아내와 아들이......!","JPN":"ダ、ダメだ！俺の家が……！あそこには妻と息子が……！","ENG":"N-no! My house! My wife, my son!","TWN":"不、不要！那是我家啊……！我的老婆和兒子都在那裡……！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체들만 아니었어도...... 내 친구들은 죽지 않았을 거야......","JPN":"侵食体さえいなければ……、友が死ぬことはなかった……","ENG":"If it wasn't for the C.O.... my friends would have never died...","TWN":"要不是侵蝕體……我的朋友就根本不會死……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체 때문에 고향이 쑥대밭이 됐어. 이제 다 끝났다고!","JPN":"侵食体のせいで故郷が廃墟になった。すべて終わったんだ！","ENG":"My hometown was devastated because of the C.O. It's all over now!","TWN":"因為侵蝕體，我的家鄉成了一片廢墟，一切都結束了。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>......침식체를 죽여. 침식체들을 증오해......! 전부 죽이는 거야......!!</color>","JPN":"<color=#ff3636>……侵食体を殺せ。侵食体を憎め……！すべて殺すんだ……！！</color>","ENG":"<color=#ff3636>Kill the C.O. Hate the C.O.! Kill them all!</color>","TWN":"<color=#ff3636>……殺掉侵蝕體，憎恨侵蝕體……！把他們全部殺掉……！！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>복수해. 전부 없애버리자.</color>","JPN":"<color=#ff3636>復讐しろ。すべて消してしまえ。</color>","ENG":"<color=#ff3636>Take revenge. Let's get rid of them all.</color>","TWN":"<color=#ff3636>我要報仇，我要讓他們通通消失。</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"<color=#ff3636>없애버려!!!</color>","JPN":"<color=#ff3636>消してしまえ！！！</color>","ENG":"<color=#ff3636>Get rid of them all!</color>","TWN":"<color=#ff3636>消失吧！！！</color>"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"헉...... 헉......","JPN":"はあ……、はあ……","ENG":"*Pant* *Pant*","TWN":"哈……哈……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"괜찮아, 오르카?","JPN":"大丈夫、オルカ？","ENG":"Are you okay, Orca?","TWN":"沒事吧，奧爾卡？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......또 그 <color=#ff3636>오르카</color>가 다른 숙주들의 기억을 보여준 거야?","JPN":"……また、その<color=#ff3636>オルカ</color>が、他の宿主の記憶を蘇らせたの？","ENG":"Did that <color=#ff3636>Orca</color> show you the memories of other hosts again?","TWN":"……<color=#ff3636>奧爾卡</color>又給妳看了其他宿主的記憶嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......응.","JPN":"……うん。","ENG":"Yeah.","TWN":"……嗯。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 녀석도 참 집요하구만.","JPN":"そいつ、本当にしつけえな。","ENG":"That's a persistent one.","TWN":"這傢伙可真是執著。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"지금처럼 의뢰를 받으면서 처치하는 것만으론 만족할 수 없단 건가?","JPN":"今みたいに、依頼を引き受けて倒すだけじゃ満足できないってのか？","ENG":"Is it not satisfied with just killing C.O. from our jobs?","TWN":"光靠現在委託的殺戮，他還是不能滿足嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......<color=#ff3636>오르카</color>는 한 번도 만족한 적 없어.","JPN":"……<color=#ff3636>オルカ</color>は一度も満足したことがないの。","ENG":"<color=#ff3636>Orca</color> has never been satisfied.","TWN":"……<color=#ff3636>奧爾卡</color>從來就沒有滿足過。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"항상 사냥에 굶주려있으니까. 다른 걸로 진정시키는 것뿐이야.","JPN":"いつも狩りに飢えてるから、他のもので落ち着かせてるだけ。","ENG":"It's always hungry for more hunts. I just calm it down by other means.","TWN":"它一直都渴望著獵殺，所以只能用其他事情讓他靜下來。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......자, 실컷 자느라 배고플 텐데 일단 밥이나 먹자.","JPN":"……ほら、たくさん寝たからお腹空いたでしょ？ご飯にしよう。","ENG":"Well, you must be starving from sleeping so much. Let's eat first.","TWN":"……來吧，妳睡了一天也該餓了，先吃個飯吧。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어...... 설마 또 네가 요리한 거야?","JPN":"おい……、まさか、またお前が飯作ったのか？","ENG":"Uh... Did you cook something again?","TWN":"呃……飯該不會又是妳做的吧？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"뭐야, 왜 그딴 표정을 지어? 내 리소토가 어때서?","JPN":"何よ、その顔！私のリゾットに文句でもあるの？","ENG":"Huh? What's with that face? You don't like my risotto?","TWN":"幹嘛，那個表情是怎樣？我做的燉飯不好吃嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카 때문에 만드는 거거든? 누가 너 좋으라고 해주는 건 줄 알아?!","JPN":"あんたのためじゃなくて、オルカのために作ったんだから！","ENG":"I made them for Orca! Did you think I would make anything for you?!","TWN":"我是為奧爾卡做的，又不是做來讓你高興的！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"싫으면 그냥 굶으라고!","JPN":"食べたくないなら、ご飯抜きよ！","ENG":"If you don't like it, just starve!","TWN":"不想吃就餓肚子吧！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"아 아니, 난 그냥...... 맛있겠다고......","JPN":"い、いや、俺はただ……、うまそうだなって……","ENG":"N-no, I just wanted to say... that it looks delicious...","TWN":"沒、沒有啦。我是說……看起來真好吃……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......<color=#ff3636>오르카</color>가 맛없대.","JPN":"……<color=#ff3636>オルカ</color>がまずいって。","ENG":"<color=#ff3636>Orca</color> says that it tastes bad.","TWN":"……<color=#ff3636>奧爾卡</color>說不好吃。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"<color=#ff3636>오르카</color>는 달콤한 걸 먹고 싶어해.","JPN":"<color=#ff3636>オルカ</color>は、甘いものが好きなの……","ENG":"<color=#ff3636>Orca</color> wants to eat something sweet.","TWN":"<color=#ff3636>奧爾卡</color>想吃甜的東西。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"......아, 앗! 그렇지! 저번에 사둔 초콜릿이 여기 어디쯤에 있었는데......","JPN":"……あ、あっ！そうだ！この前、買っておいたチョコレートが確かここら辺に……","ENG":"Oh, ah! That's right! There should be some chocolate I bought last time...","TWN":"……啊，對了！上次買的巧克力好像放在這附近……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"쳇......","JPN":"チッ……","ENG":"Tsk...","TWN":"切……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"짠, 여기 있어. 군용 초콜릿은 별로라고 하길래 고급으로 샀다고.","JPN":"ほら、チョコレートだ。軍用はまずいって言ってたから、高いやつを買ったんだ。","ENG":"Ta-da, here you go. I got a gourmet chocolate since Orca didn't like the military ones.","TWN":"鏘鏘，在這裡呢。因為軍用巧克力被說不好吃，所以我特地買了高級品呢。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"야, 야, 뭐 하는 거야? 왜 멀쩡한 초콜릿을 쪼개서 밥에다 넣어?","JPN":"お、おい、何してるんだ？何でチョコレートをリゾットに入れるんだよ？","ENG":"Hey, hey, what are you doing? Why are you mixing the chocolate with rice?","TWN":"喂，喂，妳在幹嘛？好端端的，幹嘛把巧克力拌到飯裡面？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......난 제시카가 해주는 음식 좋아.","JPN":"……ジェシカの手料理、好き。","ENG":"I like Jessica's food.","TWN":"……我喜歡潔西卡做的飯。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까, <color=#ff3636>오르카</color>랑 타협한 거야.","JPN":"だから<color=#ff3636>オルカ</color>と半分こしたの。","ENG":"So, I compromised with <color=#ff3636>Orca</color>.","TWN":"所以我已經向<color=#ff3636>奧爾卡</color>妥協了。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"어......어? 정말로?","JPN":"えっ……、ええ？本当？","ENG":"Uh... eh? Really?","TWN":"呃……什麼？真的嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"그런데...... 마음은 고맙지만, 비주얼이 좀 그렇지 않나?","JPN":"ありがとう……、でも、見た目がちょっと……？","ENG":"Although... I really appreciate that, doesn't it look a bit nasty?","TWN":"……妳的心意我心領了，但這個賣相有點太那個了吧？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"괜찮아. 이렇게 먹으면 맛있어.","JPN":"大丈夫。これ、おいしいよ。","ENG":"It's fine. I like eating it like this.","TWN":"沒關係，這樣吃也很好吃。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......냠.","JPN":"……もぐ。","ENG":"*Yum*","TWN":"……我吃。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"하...하...... 난 잠깐 화장실에 좀 다녀와야겠다.","JPN":"は…はは……俺、ちょっと便所行ってくるわ。","ENG":"Hah... hah... I'm going to hit the bathroom.","TWN":"哈……哈……我去趟廁所。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ORCA_SAD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};